import{_ as e,o as a,c as o,a2 as l}from"./chunks/framework.CMAFtOGK.js";const _=JSON.parse('{"title":"05 建设道路初步探索","description":"政治理论 · 05 建设道路初步探索","frontmatter":{"title":"05 建设道路初步探索","description":"政治理论 · 05 建设道路初步探索","category":"politics-note"},"headers":[],"relativePath":"posts/politics/notes/05-建设道路初步探索.md","filePath":"posts/politics/notes/05-建设道路初步探索.md","lastUpdated":1784753089000}'),r={name:"posts/politics/notes/05-建设道路初步探索.md"};function s(n,t,i,d,c,h){return a(),o("div",null,[...t[0]||(t[0]=[l('<h1 id="_05-社会主义建设道路初步探索的理论成果" tabindex="-1">05 社会主义建设道路初步探索的理论成果 <a class="header-anchor" href="#_05-社会主义建设道路初步探索的理论成果" aria-label="Permalink to &quot;05 社会主义建设道路初步探索的理论成果&quot;">​</a></h1><blockquote><p>🎯 <strong>一句话</strong>：以苏为鉴，走自己的路；正确处理十大关系；正确处理人民内部矛盾。</p></blockquote><hr><h2 id="一、重要文献与观点" tabindex="-1">一、重要文献与观点 <a class="header-anchor" href="#一、重要文献与观点" aria-label="Permalink to &quot;一、重要文献与观点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">文献/会议</th><th style="text-align:left;">核心观点</th></tr></thead><tbody><tr><td style="text-align:left;">《论十大关系》（1956）</td><td style="text-align:left;">调动一切积极因素为社会主义事业服务；以苏为鉴</td></tr><tr><td style="text-align:left;">党的八大（1956）</td><td style="text-align:left;">主要矛盾：人民对于经济文化迅速发展的需要同当前经济文化不能满足人民需要的状况之间的矛盾；主要任务是发展生产力</td></tr><tr><td style="text-align:left;">《关于正确处理人民内部矛盾的问题》（1957）</td><td style="text-align:left;">两类矛盾；人民内部矛盾用民主方法（团结—批评—团结）</td></tr></tbody></table><hr><h2 id="二、正反两方面" tabindex="-1">二、正反两方面 <a class="header-anchor" href="#二、正反两方面" aria-label="Permalink to &quot;二、正反两方面&quot;">​</a></h2><ul><li><strong>积极成果</strong>：独立的比较完整的工业体系和国民经济体系；“两弹一星”等</li><li><strong>曲折教训</strong>：要科学判断国情与主要矛盾，坚持实事求是，按客观经济规律办事</li></ul><hr><h2 id="三、闭卷挑战" tabindex="-1">三、闭卷挑战 <a class="header-anchor" href="#三、闭卷挑战" aria-label="Permalink to &quot;三、闭卷挑战&quot;">​</a></h2><p><strong>1.</strong> 党的八大指出当时国内主要矛盾是什么？</p><blockquote><p><strong>点击查看答案与解析</strong> 人民对于经济文化迅速发展的需要同当前经济文化不能满足人民需要的状况之间的矛盾。</p></blockquote><p><strong>2.</strong> 正确处理人民内部矛盾的基本方法是什么？</p><blockquote><p><strong>点击查看答案与解析</strong> 民主的方法，即团结—批评—团结。</p></blockquote><p>返回：04-社会主义改造 · <a href="/zhuan-sheng-ben-notes/posts/politics/">政治</a></p>',15)])])}const g=e(r,[["render",s]]);export{_ as __pageData,g as default};
